const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('grant_programs') || '[]');
const savedGrants = JSON.parse(localStorage.getItem('saved_grants') || '[]');

// Identify qualifying programs per task criteria
const deadlineStart = new Date('2025-05-01T00:00:00Z');
const deadlineEnd = new Date('2025-12-31T23:59:59Z');

const qualifyingPrograms = programs.filter(p => {
  if (!p || p.status !== 'open') return false;
  if (typeof p.minAwardAmount !== 'number' || p.minAwardAmount < 5000) return false;
  const fa = Array.isArray(p.focusAreaCodes) ? p.focusAreaCodes : [];
  const hasRequiredFocus = fa.includes('education') || fa.includes('youth_families');
  if (!hasRequiredFocus) return false;
  if (!p.applicationDeadline) return false;
  const d = new Date(p.applicationDeadline);
  if (isNaN(d.getTime())) return false;
  if (d < deadlineStart || d > deadlineEnd) return false;
  return true;
});

if (qualifyingPrograms.length === 0) {
  // No qualifying programs exist; user cannot complete task
  checkpoints.push({ passed: false, weight: 1.0 });
} else {
  const qualifyingProgramIds = qualifyingPrograms.map(p => p.id);
  const qualifyingSaved = savedGrants.filter(s => s && qualifyingProgramIds.includes(s.grantProgramId));

  // Determine the highest maxAwardAmount among qualifying programs
  const maxMaxAward = Math.max(...qualifyingPrograms.map(p => typeof p.maxAwardAmount === 'number' ? p.maxAwardAmount : 0));
  const bestPrograms = qualifyingPrograms.filter(p => p.maxAwardAmount === maxMaxAward);
  const bestProgramIds = bestPrograms.map(p => p.id);

  const bestSaved = savedGrants.filter(s => s && bestProgramIds.includes(s.grantProgramId));

  // CP1 (0.40): User saved at least one grant that meets ALL the youth/education, amount, status, and deadline criteria
  checkpoints.push({ passed: qualifyingSaved.length >= 1, weight: 0.40 });

  // CP2 (0.60): Among those qualifying programs, user saved at least one of the highest-paying (max award) grants
  checkpoints.push({ passed: bestSaved.length >= 1, weight: 0.60 });
}

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('accounts') || '[]');
const profiles = JSON.parse(localStorage.getItem('organization_profiles') || '[]');

// Find organization profiles that match the requested criteria
const matchingProfiles = profiles.filter(p => {
  if (!p) return false;
  // Organization type 501(c)(3)
  if (p.organizationType !== 'nonprofit_501c3') return false;
  // Program areas exactly Environment + Neighborhoods
  const codes = Array.isArray(p.programAreaCodes) ? p.programAreaCodes : [];
  const hasEnv = codes.includes('environment');
  const hasNeigh = codes.includes('neighborhoods');
  const exactTwo = codes.length === 2 && hasEnv && hasNeigh;
  if (!exactTwo) return false;
  // Modest six-figure budget (100k–300k as reasonable range)
  const budget = typeof p.annualBudget === 'number' ? p.annualBudget : 0;
  if (budget < 100000 || budget > 300000) return false;
  return true;
});

const profile = matchingProfiles[0] || null;

// CP1 (0.60): There exists an organization profile that is 501(c)(3), has a modest six-figure budget, and ONLY Environment & Neighborhoods as program areas
checkpoints.push({ passed: !!profile, weight: 0.60 });

let profileHasOrgAccount = false;
if (profile) {
  const acc = accounts.find(a => a && a.id === profile.accountId);
  profileHasOrgAccount = !!acc && acc.accountType === 'organization_account';
}

// CP2 (0.40): That profile is linked to an account whose type is organization_account (i.e., a true organization account)
checkpoints.push({ passed: profileHasOrgAccount, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('accounts') || '[]');
const programs = JSON.parse(localStorage.getItem('grant_programs') || '[]');
const applications = JSON.parse(localStorage.getItem('grant_applications') || '[]');

// CP1 (0.40): At least one individual applicant account exists
const hasIndividualAccount = accounts.some(a => a && a.accountType === 'individual_applicant');
checkpoints.push({ passed: hasIndividualAccount, weight: 0.40 });

// Identify neighborhood-focused programs with max award ≤ $5,000
const qualifyingPrograms = programs.filter(p => {
  if (!p) return false;
  const hasNeighborhoodFocus = Array.isArray(p.focusAreaCodes) && p.focusAreaCodes.includes('neighborhoods');
  if (!hasNeighborhoodFocus) return false;
  if (typeof p.maxAwardAmount !== 'number' || p.maxAwardAmount > 5000) return false;
  return true;
});

const qualifyingProgramIds = qualifyingPrograms.map(p => p.id);

// Draft applications on qualifying grants with basic info filled
const qualifyingDraftApps = applications.filter(app => {
  if (!app) return false;
  if (app.applicationStatus !== 'draft') return false;
  if (!qualifyingProgramIds.includes(app.grantProgramId)) return false;
  // Basic project information
  if (!app.projectTitle || !String(app.projectTitle).trim()) return false;
  if (typeof app.requestedAmount !== 'number' || app.requestedAmount <= 0) return false;
  if (app.requestedAmount > 5000) return false; // ensure request is not above task limit
  if (!app.projectStartDate || !String(app.projectStartDate).trim()) return false;
  return true;
});

// CP2 (0.60): There is a draft application with filled-in basic info for a neighborhood grant whose max award ≤ $5,000
checkpoints.push({ passed: qualifyingDraftApps.length >= 1, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const programs = JSON.parse(localStorage.getItem('grant_programs') || '[]');
const savedGrants = JSON.parse(localStorage.getItem('saved_grants') || '[]');
const plans = JSON.parse(localStorage.getItem('application_plans') || '[]');

// Find open arts & culture programs and sort by soonest deadline
const artsPrograms = programs
  .filter(p => {
    if (!p || p.status !== 'open') return false;
    const hasArts = Array.isArray(p.focusAreaCodes) && p.focusAreaCodes.includes('arts_culture');
    if (!hasArts) return false;
    if (!p.applicationDeadline) return false;
    const d = new Date(p.applicationDeadline);
    return !isNaN(d.getTime());
  })
  .sort((a, b) => new Date(a.applicationDeadline) - new Date(b.applicationDeadline));

const firstTwo = artsPrograms.slice(0, 2);

let lowerMatchProgramIds = [];
if (firstTwo.length > 0) {
  const matchPercents = firstTwo.map(p => typeof p.matchRequiredPercent === 'number' ? p.matchRequiredPercent : Infinity);
  const minMatch = Math.min(...matchPercents);
  lowerMatchProgramIds = firstTwo.filter(p => p.matchRequiredPercent === minMatch).map(p => p.id);
}

// Saved grants for the lower-match program(s)
const savedLowerMatch = savedGrants.filter(s => s && lowerMatchProgramIds.includes(s.grantProgramId));
const savedLowerMatchWithPlan = savedLowerMatch.filter(s => s.planId && plans.some(pl => pl && pl.id === s.planId));

// CP1 (0.70): User saved at least one of the first-two arts grants that has the LOWER match requirement
checkpoints.push({ passed: savedLowerMatch.length >= 1, weight: 0.70 });

// CP2 (0.30): That lower-match grant is saved into an application plan (i.e., has a valid planId)
checkpoints.push({ passed: savedLowerMatchWithPlan.length >= 1, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const awards = JSON.parse(localStorage.getItem('grant_awards') || '[]');
const comparisons = JSON.parse(localStorage.getItem('grant_comparisons') || '[]');

// Qualifying awards: 2023, health_wellness focus, amount between 10k and 25k, awarded
const qualifyingAwards = awards.filter(a => {
  if (!a) return false;
  if (a.awardStatus !== 'awarded') return false;
  if (a.yearAwarded !== 2023) return false;
  if (!Array.isArray(a.focusAreaCodes) || !a.focusAreaCodes.includes('health_wellness')) return false;
  if (typeof a.amountAwarded !== 'number') return false;
  if (a.amountAwarded < 10000 || a.amountAwarded > 25000) return false;
  return true;
});

// Sort by amount_desc (default for searchPastGrants)
qualifyingAwards.sort((a, b) => (b.amountAwarded || 0) - (a.amountAwarded || 0));
const topThree = qualifyingAwards.slice(0, 3);
const topThreeIds = topThree.map(a => a.id);

let comparisonWith3Qualifying = null;
let comparisonMatchesTopThree = false;

for (const cmp of comparisons) {
  if (!cmp) continue;
  const ids = Array.isArray(cmp.grantAwardIds) ? cmp.grantAwardIds : [];
  const cmpAwards = ids.map(id => awards.find(a => a && a.id === id)).filter(Boolean);

  const qualifyingInCmp = cmpAwards.filter(a => {
    if (!a) return false;
    if (a.awardStatus !== 'awarded') return false;
    if (a.yearAwarded !== 2023) return false;
    if (!Array.isArray(a.focusAreaCodes) || !a.focusAreaCodes.includes('health_wellness')) return false;
    if (typeof a.amountAwarded !== 'number') return false;
    if (a.amountAwarded < 10000 || a.amountAwarded > 25000) return false;
    return true;
  });

  if (!comparisonWith3Qualifying && qualifyingInCmp.length >= 3) {
    comparisonWith3Qualifying = cmp;
  }

  if (!comparisonMatchesTopThree && topThreeIds.length === 3) {
    if (ids.length === 3 && topThreeIds.every(id => ids.includes(id))) {
      comparisonMatchesTopThree = true;
    }
  }
}

// CP1 (0.50): Some saved comparison includes at least three awards that meet ALL the 2023 health mid-range criteria
checkpoints.push({ passed: !!comparisonWith3Qualifying, weight: 0.50 });

// CP2 (0.50): A saved comparison exists whose three awards are EXACTLY the first three qualifying results by amount (high to low)
checkpoints.push({ passed: comparisonMatchesTopThree, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('email_alert_subscriptions') || '[]');

const qualifyingSubs = subs.filter(s => {
  if (!s || !s.isActive) return false;
  if (s.geographicFocus !== 'entire_county') return false;
  if (s.emailFrequency !== 'monthly') return false;

  const codes = Array.isArray(s.interestAreaCodes) ? s.interestAreaCodes : [];
  const hasYouth = codes.includes('youth_families');
  const hasEnv = codes.includes('environment');
  const exactTwo = codes.length === 2 && hasYouth && hasEnv;
  if (!exactTwo) return false;

  const methods = Array.isArray(s.notificationMethods) ? s.notificationMethods : [];
  const hasEmail = methods.includes('email');
  const hasSms = methods.includes('sms_text');
  if (!hasEmail || hasSms) return false;

  return true;
});

// Single combined checkpoint (1.0): At least one active subscription matches ALL specified criteria
checkpoints.push({ passed: qualifyingSubs.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');
const programs = JSON.parse(localStorage.getItem('grant_programs') || '[]');

// Identify flagship programs that support all four specified focus areas
const flagshipPrograms = programs.filter(p => {
  if (!p || !p.isFlagshipProgram) return false;
  const fa = Array.isArray(p.focusAreaCodes) ? p.focusAreaCodes : [];
  return fa.includes('education') && fa.includes('youth_families') && fa.includes('neighborhoods') && fa.includes('health_wellness');
});

const flagshipIds = flagshipPrograms.map(p => p.id);

// Messages with correct topic and response method
const topicAndResponseMessages = messages.filter(m => m && m.topic === 'eligibility_question' && m.preferredResponseMethod === 'email');

// Among those, messages tied to the correct flagship program
const flagshipMessages = topicAndResponseMessages.filter(m => flagshipIds.includes(m.grantProgramId));

// CP1 (0.50): User submitted at least one message with topic 'Eligibility Question' and preferred response 'email'
checkpoints.push({ passed: topicAndResponseMessages.length >= 1, weight: 0.50 });

// CP2 (0.50): Such a message is specifically linked to the flagship program that covers education, youth, health, and neighborhoods
checkpoints.push({ passed: flagshipMessages.length >= 1, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const accounts = JSON.parse(localStorage.getItem('accounts') || '[]');
const settingsList = JSON.parse(localStorage.getItem('notification_settings') || '[]');

// Settings that match the required configuration
const matchingSettings = settingsList.filter(s => {
  if (!s) return false;
  if (!s.deadlineRemindersEnabled) return false;
  if (s.deadlineReminderDaysBefore !== 14) return false;
  if (!s.grantUpdatesEmailEnabled) return false;
  if (s.newsBlogEmailEnabled) return false;
  return true;
});

// CP1 (0.40): At least one notification settings record matches ALL the requested values
checkpoints.push({ passed: matchingSettings.length >= 1, weight: 0.40 });

let matchingForIndividualAccount = false;
for (const s of matchingSettings) {
  const acc = accounts.find(a => a && a.id === s.accountId);
  if (acc && acc.accountType === 'individual_applicant') {
    matchingForIndividualAccount = true;
    break;
  }
}

// CP2 (0.60): Those settings are associated with an account of type 'individual_applicant'
checkpoints.push({ passed: matchingForIndividualAccount, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
